import { runCompEngine } from "./compEngine"
import { runArvEngine } from "./arvEngine"
import { runDomEngine } from "./domEngine"

export function evaluateDeal(deal: any, comps:any[], rules:any) {
  const failures = []

  const { selected } = runCompEngine(deal, comps, rules)

  if (selected.length === 0) {
    failures.push("No valid COMPs")
  }

  const { arv } = runArvEngine(selected)

  const domCheck = runDomEngine(selected, rules.MAX_COMP_DOM)
  if (!domCheck.pass) failures.push(domCheck.reason)

  const profitPercent = ((arv - deal.price) / arv) * 100

  if (profitPercent < rules.MIN_PROFIT_PERCENT) {
    failures.push("Profit below minimum threshold")
  }

  return {
    status: failures.length ? "FAIL" : "PASS",
    arv,
    profitPercent: Math.round(profitPercent),
    comps: selected,
    failureReasons: failures
  }
}
