export function runCompEngine(subject : any, comps: any[], rules: any) {
  const selected = []
  const rejected = []

  for (const comp of comps) {
    if (comp.distance > rules.MAX_COMP_DISTANCE) {
      rejected.push({ comp, reason: "Distance too far" })
      continue
    }

    if (comp.dom > rules.MAX_COMP_DOM) {
      rejected.push({ comp, reason: "DOM too high" })
      continue
    }

    selected.push(comp)
  }

  return { selected, rejected }
}
